// // This module implements a 4-bit shift register that captures a serial input signal on each negative edge of the clock. When the reset signal is activated, the shift register is cleared to zero. Otherwise, it shifts the current contents right by one bit, inserting the new serial input at the most significant bit while maintaining the previous bits.
module top_module(
    input clk,
    input reset,
    input serial_in,
    output [3:0] parallel_out
);reg [3:0] shift_reg;

always @(posedge clk) begin
    if (reset) begin
        shift_reg <= 4'b0;
    end else begin
        shift_reg <= {shift_reg[2:0], serial_in};
    end
end

assign parallel_out = shift_reg;

endmodule
